'use client';

import { useState, useEffect, useMemo } from 'react';
import { Input, Space, Breadcrumb, Card, Tag, Badge, App } from 'antd';
import { PlusOutlined, SearchOutlined, EditOutlined, FileExcelOutlined } from '@ant-design/icons';
import { AppButton } from '@/app/components/common/AppButton';
import { AppGrid } from '@/app/components/common/AppGrid';
import { useTranslation } from 'react-i18next';
import { getUsersApi } from '@/services/userService';
import type { ColumnsType } from 'antd/es/table';
import { useAppGridSearch } from '@/app/components/common/AppGridSearch';
import { FormModal, UserDataType } from './FormModal';
import { Can } from '@/lib/PermissionProvider';
import { AccessGuard } from '@/lib/AccessGuard';

export default function UserListPage() {
    const { t } = useTranslation();
    const { message } = App.useApp();
    const { getColumnSearchProps } = useAppGridSearch();

    const [users, setUsers] = useState<UserDataType[]>([]);
    const [loading, setLoading] = useState(false);
    const [total, setTotal] = useState(0);
    const [searchText, setSearchText] = useState('');
    const [currentPagination, setCurrentPagination] = useState({ current: 1, pageSize: 10 });

    const [modalOpen, setModalOpen] = useState(false);
    const [editingUser, setEditingUser] = useState<UserDataType | null>(null);

    // ── Fetch danh sách user ──────────────────────────────────────────────────
    const fetchData = async (page: number, size: number) => {
        setLoading(true);
        try {
            const data = await getUsersApi(page, size);
            if (data?.items) {
                setUsers(data.items);
                setTotal(data.totalCount || 0);
            } else if (Array.isArray(data)) {
                setUsers(data);
                setTotal(data.length);
            }
        } catch (error: any) {
            message.error(error.message || t('error_load_data') || 'Lỗi khi tải dữ liệu');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData(currentPagination.current, currentPagination.pageSize);
    }, [currentPagination]);

    // ── Global search ─────────────────────────────────────────────────────────
    const filteredData = useMemo(() => {
        return users.filter((item) => {
            if (!searchText) return true;
            return Object.values(item).some(
                (val) => val?.toString().toLowerCase().includes(searchText.toLowerCase())
            );
        });
    }, [users, searchText]);

    // ── Modal handlers ────────────────────────────────────────────────────────
    const handleOpenAdd = () => {
        setEditingUser(null);
        setModalOpen(true);
    };

    const handleOpenEdit = (user: UserDataType) => {
        setEditingUser(user);
        setModalOpen(true);
    };

    const handleModalClose = () => setModalOpen(false);

    const handleModalSuccess = () => {
        fetchData(currentPagination.current, currentPagination.pageSize);
    };

    // ── Table columns ─────────────────────────────────────────────────────────
    const columns: ColumnsType<UserDataType> = [
        {
            title: <span className="text-white font-semibold">{t('actions')}</span>,
            key: 'action',
            width: 100,
            align: 'center',
            fixed: 'left',
            render: (_, record) => (
                <Space size="small">
                    <Can I="AdministrationService.Users.Update">
                        <AppButton btnType="edit" icon={<EditOutlined />} data={record} onClick={() => handleOpenEdit(record)} />
                    </Can>
                </Space>
            ),
        },
        {
            ...getColumnSearchProps('userName', t('user_name')),
            dataIndex: 'userName',
            key: 'userName',
            width: 140,
            align: 'center',
            render: (text) => <span className="font-medium text-[#00b5ad]">{text}</span>,
        },
        {
            ...getColumnSearchProps('fullName', t('full_name')),
            dataIndex: 'fullName',
            key: 'fullName',
            width: 160,
            align: 'center',
            render: (text) => text || <span className="text-gray-300 italic">—</span>,
        },
        {
            ...getColumnSearchProps('email', t('email')),
            dataIndex: 'email',
            key: 'email',
            width: 200,
            align: 'center',
        },
        {
            title: <span className="text-white font-semibold">{t('phone_number')}</span>,
            dataIndex: 'phoneNumber',
            key: 'phoneNumber',
            width: 140,
            align: 'center',
            render: (text) => text || <span className="text-gray-300 italic">—</span>,
        },
        {
            title: <span className="text-white font-semibold">{t('role')}</span>,
            dataIndex: 'roles',
            key: 'roles',
            width: 180,
            align: 'center',
            render: (roles: string[]) =>
                roles && roles.length > 0 ? (
                    <Space size={4} wrap>
                        {roles.map((r) => (
                            <Tag
                                key={r}
                                color={r.toLowerCase().includes('admin') ? 'gold' : 'blue'}
                                style={{ borderRadius: 20, margin: 0 }}
                            >
                                {r}
                            </Tag>
                        ))}
                    </Space>
                ) : (
                    <span className="text-gray-300 italic">—</span>
                ),
        },
        {
            title: <span className="text-white font-semibold">{t('status')}</span>,
            dataIndex: 'isActive',
            key: 'isActive',
            width: 130,
            align: 'center',
            filters: [
                { text: t('status_active'), value: true },
                { text: t('status_inactive'), value: false },
            ],
            onFilter: (value, record) => record.isActive === value,
            render: (isActive: boolean) => (
                <Badge
                    status={isActive ? 'success' : 'default'}
                    text={
                        <span className={isActive ? 'text-green-600 font-medium' : 'text-gray-400'}>
                            {isActive ? t('status_active') : t('status_inactive')}
                        </span>
                    }
                />
            ),
        },
    ];

    // ── Render ────────────────────────────────────────────────────────────────
    return (
        <AccessGuard feature="Feature.Administration.Users" permission="AdministrationService.Users.View">
            <div className="flex flex-col gap-4">
                <Breadcrumb items={[{ title: t('system_admin') }, { title: t('user_management') }]} />

                <div className="flex justify-between items-center">
                    <h1 className="text-xl font-semibold text-gray-800 m-0">{t('user_list_title')}</h1>
                </div>

                <Card className="shadow-sm border-none overflow-hidden" style={{ borderRadius: 6 }}>
                    <div className="mb-4 flex justify-end items-center px-2">
                        <Space>
                            <Input
                                placeholder={t('searchText')}
                                prefix={<SearchOutlined />}
                                style={{ width: 250 }}
                                className="rounded-md"
                                value={searchText}
                                onChange={(e) => setSearchText(e.target.value)}
                            />
                            <Can I="AdministrationService.Users.Create">
                                <AppButton
                                    btnType="add"
                                    icon={<PlusOutlined />}
                                    title={`${t('add')} ${t('user')}`}
                                    onClick={handleOpenAdd}
                                />
                            </Can>
                            <Can I="AdministrationService.Users.Export">
                                <AppButton btnType="export" icon={<FileExcelOutlined />} title={t('export')} />
                            </Can>
                        </Space>
                    </div>

                    <AppGrid
                        loading={loading}
                        columns={columns}
                        dataSource={filteredData}
                        rowKey="id"
                        pagination={{
                            current: currentPagination.current,
                            pageSize: currentPagination.pageSize,
                            total: total,
                            onChange: (page, pageSize) => {
                                setCurrentPagination({ current: page, pageSize });
                            },
                        }}
                    />
                </Card>

                {/* Modal Add / Edit — dùng chung 1 component */}
                <FormModal
                    open={modalOpen}
                    editingUser={editingUser}
                    onSuccess={handleModalSuccess}
                    onClose={handleModalClose}
                />
            </div>
        </AccessGuard>
    );
}